import React, { useState } from 'react';
import { Dashboard } from './components/Dashboard';
import { Observatory } from './components/Observatory';
import { Risks } from './components/Risks';
import { ResourceManager, ColumnDef, FormField } from './components/ResourceManager';
import { TabName, NewsItem } from './types';
import { 
  LayoutDashboard, 
  TriangleAlert, 
  Code2, 
  Zap, 
  Bug, 
  Bell, 
  BookOpen, 
  ShieldCheck, 
  Eye, 
  ClipboardList,
  Menu,
  X
} from 'lucide-react';

// --- CONFIGURATIONS FOR GENERIC MODULES ---

const INCIDENTS_CONFIG = {
  columns: [
    { header: 'Fecha', accessor: 'date', type: 'date' },
    { header: 'Entidad', accessor: 'entity' },
    { header: 'País', accessor: 'country', type: 'badge', badgeColors: { 'Argentina': 'bg-blue-100 text-blue-800' } },
    { header: 'Sector', accessor: 'sector' },
    { header: 'Tipo', accessor: 'type' },
    { header: 'Actor', accessor: 'actor' },
  ] as ColumnDef[],
  fields: [
    { label: 'Fecha', name: 'date', type: 'date', required: true },
    { label: 'Tipo', name: 'type', type: 'select', options: ['DataBreach', 'Ransomware', 'CyberAttack', 'Phishing', 'Defacement'], required: true },
