export const fetchDigest = async (days: number): Promise<NewsItem[]> => {
  try {
    const controller = new AbortController();
    const timeoutId = setTimeout(() => controller.abort(), 3000);

    const response = await fetch(`http://localhost:5000/generate-cybersecurity-digest?days=${days}`, {
      signal: controller.signal
    });

    clearTimeout(timeoutId);

    if (response.ok) {
      const data = await response.json();
      return data;
    }
    throw new Error("Server response not ok");
  } catch (error) {
    console.warn("Backend not available, using mock data for Digest.", error);
    await new Promise(resolve => setTimeout(resolve, 800));
    return MOCK_NEWS;
  }
