export const fetchTickets = async (): Promise<RiskTicket[]> => {
  const stored = localStorage.getItem('tickets_v8');
  if (stored) return JSON.parse(stored);
  localStorage.setItem('tickets_v8', JSON.stringify(MOCK_TICKETS));
  return MOCK_TICKETS;
};

export const saveTicket = async (ticket: RiskTicket): Promise<void> => {
  const tickets = await fetchTickets();
  const existingIndex = tickets.findIndex(t => t.id === ticket.id);

  if (existingIndex >= 0) {
    tickets[existingIndex] = ticket;
  } else {
    tickets.unshift(ticket);
  }

  MOCK_TICKETS = tickets; 
  localStorage.setItem('tickets_v8', JSON.stringify(tickets));
};

export const deleteTicket = async (id: number): Promise<void> => {
  const tickets = await fetchTickets();
  const filtered = tickets.filter(t => t.id !== id);
  MOCK_TICKETS = filtered;
  localStorage.setItem('tickets_v8', JSON.stringify(filtered));
};

export const addTicketComment = async (ticketId: number, text: string): Promise<void> => {
  const tickets = await fetchTickets();
  const ticket = tickets.find(t => t.id === ticketId);
  if (ticket) {
    ticket.activity.push({
      type: 'comment',
      timestamp: Date.now(),
      text
    });
    ticket.lastUpdated = Date.now();

    const index = tickets.findIndex(t => t.id === ticketId);
    tickets[index] = ticket;
    MOCK_TICKETS = tickets;
    localStorage.setItem('tickets_v8', JSON.stringify(tickets));
  }
};

// --- Generic Resource API (For Incidents, Exploits, etc.) ---

export const fetchResources = async <T>(key: string): Promise<T[]> => {
  const stored = localStorage.getItem(`resource_${key}`);
  if (stored) return JSON.parse(stored);

  // Seed data if empty
  const seed = SEED_DATA[key] || [];
  localStorage.setItem(`resource_${key}`, JSON.stringify(seed));
  return seed;
};

export const saveResource = async (key: string, item: any): Promise<void> => {
  const items = await fetchResources<any>(key);
  const index = items.findIndex((i: any) => i.id === item.id);

  if (index >= 0) {
    items[index] = item;
  } else {
    // Ensure ID exists
    if (!item.id) item.id = Date.now().toString();
    items.unshift(item);
  }

  localStorage.setItem(`resource_${key}`, JSON.stringify(items));
};

export const deleteResource = async (key: string, id: string): Promise<void> => {
  const items = await fetchResources<any>(key);
  const filtered = items.filter((i: any) => i.id !== id);
  localStorage.setItem(`resource_${key}`, JSON.stringify(filtered));
};

// --- Dashboard Statistics API ---

export interface DashboardStats {
  totalIncidents: number;
  totalExploits: number;
  totalZeroDays: number;
  totalCVEs: number;
  totalAlerts: number;
  ticketsByPriority: { name: string; value: number }[];
  ticketsByStatus: { name: string; value: number }[];
}

export const fetchDashboardStats = async (): Promise<DashboardStats> => {
  const tickets = await fetchTickets();
  const incidents = await fetchResources<Incident>('incidentes');
  const exploits = await fetchResources<Exploit>('exploits');
  const zerodays = await fetchResources<ZeroDay>('zerodays');
  const cves = await fetchResources<CVE>('cves');
  const alerts = await fetchResources<Alert>('alertas');

  // Calculate stats from Risk Tickets
  const priorityCount = tickets.reduce((acc, t) => {
    acc[t.priority] = (acc[t.priority] || 0) + 1;
    return acc;
  }, {} as Record<string, number>);

  const statusCount = tickets.reduce((acc, t) => {
    acc[t.status] = (acc[t.status] || 0) + 1;
    return acc;
  }, {} as Record<string, number>);

  return {
    totalIncidents: incidents.length,
    totalExploits: exploits.length,
    totalZeroDays: zerodays.length,
    totalCVEs: cves.length,
    totalAlerts: alerts.length,
    ticketsByPriority: [
      { name: 'Alta', value: priorityCount['high'] || 0 },
      { name: 'Media', value: priorityCount['medium'] || 0 },
      { name: 'Baja', value: priorityCount['low'] || 0 },
    ],
    ticketsByStatus: [
      { name: 'Detectado', value: statusCount['detectado'] || 0 },
      { name: 'Notificado', value: statusCount['notificado'] || 0 },
      { name: 'Mitigando', value: statusCount['mitigando'] || 0 },
      { name: 'Resuelto', value: statusCount['resuelto'] || 0 },
      { name: 'Aceptado', value: statusCount['riesgo-aceptado'] || 0 },
    ]
  };
};
