import React, { useEffect, useState } from 'react';
import { fetchResources, saveResource, deleteResource } from '../services/api';
import { Plus, Search, Trash2, Edit2, FileDown, ExternalLink, Loader2 } from 'lucide-react';
import { jsPDF } from "jspdf";
import autoTableModule from 'jspdf-autotable';

// Fix for autoTable in ESM environments
const autoTable = (autoTableModule as any).default || autoTableModule;

export interface ColumnDef {
  header: string;
  accessor: string;
  type?: 'text' | 'date' | 'badge' | 'link';
  badgeColors?: Record<string, string>; // Map value to color class
}

export interface FormField {
  label: string;
  name: string;
  type: 'text' | 'date' | 'number' | 'select' | 'textarea';
  options?: string[]; // For select
  required?: boolean;
  placeholder?: string;
}

interface ResourceManagerProps {
  resourceKey: string;
  title: string;
  columns: ColumnDef[];
  formFields: FormField[];
}

export const ResourceManager: React.FC<ResourceManagerProps> = ({
  resourceKey,
  title,
  columns,
  formFields
}) => {
  const [items, setItems] = useState<any[]>([]);
  const [loading, setLoading] = useState(true);
  const [search, setSearch] = useState('');
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [editingItem, setEditingItem] = useState<any | null>(null);
  const [formData, setFormData] = useState<Record<string, any>>({});

  useEffect(() => {
    loadItems();
  }, [resourceKey]);

  const loadItems = async () => {
    setLoading(true);
    const data = await fetchResources(resourceKey);
    setItems(data);
    setLoading(false);
  };

  const resetForm = () => {
    const initialData: Record<string, any> = {};
    formFields.forEach(field => {
      initialData[field.name] = '';
    });
    setFormData(initialData);
    setEditingItem(null);
  };

  const handleOpenModal = (item?: any) => {
    if (item) {
      setEditingItem(item);
      setFormData({ ...item });
    } else {
      resetForm();
    }
    setIsModalOpen(true);
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    const newItem = {
      ...formData,
      id: editingItem ? editingItem.id : Date.now().toString()
    };

    await saveResource(resourceKey, newItem);
    setIsModalOpen(false);
    loadItems();
  };

  const handleDelete = async (id: string) => {
    if (window.confirm('¿Estás seguro de eliminar este registro?')) {
      await deleteResource(resourceKey, id);
      loadItems();
    }
  };

  const generatePdf = () => {
    const doc = new jsPDF();

    doc.setFontSize(18);
    doc.text(`Reporte de ${title}`, 14, 22);
    doc.setFontSize(10);
    doc.text(`Generado: ${new Date().toLocaleString()}`, 14, 30);

    const tableColumn = columns.map(col => col.header);
    const tableRows = filteredItems.map(item => {
      return columns.map(col => {
        if (col.type === 'date') return new Date(item[col.accessor]).toLocaleDateString();
        return item[col.accessor] || '';
      });
    });

    autoTable(doc, {
      head: [tableColumn],
      body: tableRows,
      startY: 35,
    });

    doc.save(`${title}_report.pdf`);
  };

  const filteredItems = items.filter(item => {
    if (!search) return true;
    const searchLower = search.toLowerCase();
    return columns.some(col => {
      const val = item[col.accessor];
      return val && String(val).toLowerCase().includes(searchLower);
    });
  });

  const getBadgeClass = (value: string, colors?: Record<string, string>) => {
    if (colors && colors[value]) return colors[value];

    // Default heuristics
    const v = value?.toLowerCase() || '';
    if (v.includes('high') || v.includes('crit') || v.includes('alta') || v === 'activo') return 'bg-red-100 text-red-800';
    if (v.includes('med') || v.includes('mod')) return 'bg-orange-100 text-orange-800';
    if (v.includes('low') || v.includes('baj') || v.includes('info') || v === 'mitigado') return 'bg-green-100 text-green-800';
    return 'bg-gray-100 text-gray-800';
  };

  return (
    <div className="space-y-6">
      {/* Toolbar */}
      <div className="flex flex-col sm:flex-row gap-4 justify-between items-start sm:items-center bg-white p-4 rounded-lg shadow-sm border border-gray-200">
        <h2 className="text-xl font-bold text-gray-800">{title}</h2>

        <div className="flex gap-3 w-full sm:w-auto">
          <div className="relative flex-1 sm:w-64">
            <Search className="absolute left-3 top-1/2 -translate-y-1/2 w-4 h-4 text-gray-400" />
            <input 
              type="text" 
              placeholder="Buscar..." 
              value={search}
              onChange={(e) => setSearch(e.target.value)}
              className="w-full pl-9 pr-4 py-2 border border-gray-300 rounded-md focus:ring-2 focus:ring-indigo-500 outline-none text-sm"
            />
          </div>
          <button 
            onClick={generatePdf}
            className="p-2 text-gray-600 hover:bg-gray-100 border border-gray-300 rounded-md transition-colors"
            title="Exportar PDF"
          >
            <FileDown className="w-4 h-4" />
          </button>
          <button 
            onClick={() => handleOpenModal()}
            className="bg-indigo-600 hover:bg-indigo-700 text-white px-4 py-2 rounded-md text-sm font-medium flex items-center gap-2 transition-colors whitespace-nowrap"
          >
            <Plus className="w-4 h-4" /> Nuevo
          </button>
        </div>
      </div>

      {/* Table */}
      <div className="bg-white rounded-lg shadow-sm border border-gray-200 overflow-hidden">
        <div className="overflow-x-auto">
          <table className="w-full text-left border-collapse">
            <thead className="bg-gray-50 border-b border-gray-200">
              <tr>
                {columns.map((col, idx) => (
                  <th key={idx} className="px-6 py-3 text-xs font-medium text-gray-500 uppercase tracking-wider">
                    {col.header}
                  </th>
                ))}
                <th className="px-6 py-3 text-right">Acciones</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-gray-200">
              {loading ? (
                <tr>
                  <td colSpan={columns.length + 1} className="px-6 py-8 text-center">
                    <div className="flex justify-center items-center gap-2 text-gray-500">
                      <Loader2 className="w-5 h-5 animate-spin" /> Cargando...
                    </div>
                  </td>
                </tr>
              ) : filteredItems.length === 0 ? (
                <tr>
                  <td colSpan={columns.length + 1} className="px-6 py-8 text-center text-gray-500">
                    No se encontraron registros.
                  </td>
                </tr>
              ) : (
                filteredItems.map((item, idx) => (
                  <tr key={item.id || idx} className="hover:bg-gray-50 transition-colors">
                    {columns.map((col, cIdx) => (
                      <td key={cIdx} className="px-6 py-4 text-sm text-gray-700">
                        {col.type === 'date' ? (
                           item[col.accessor] ? new Date(item[col.accessor]).toLocaleDateString() : 'N/A'
                        ) : col.type === 'badge' ? (
                          <span className={`px-2 py-1 rounded-full text-xs font-semibold ${getBadgeClass(item[col.accessor], col.badgeColors)}`}>
                            {item[col.accessor]}
                          </span>
                        ) : col.type === 'link' ? (
                          item[col.accessor] ? (
                            <a href={item[col.accessor]} target="_blank" rel="noreferrer" className="text-indigo-600 hover:text-indigo-900 flex items-center gap-1">
                              Link <ExternalLink className="w-3 h-3" />
                            </a>
                          ) : <span className="text-gray-400">-</span>
                        ) : (
                          item[col.accessor]
                        )}
                      </td>
                    ))}
                    <td className="px-6 py-4 text-right text-sm font-medium whitespace-nowrap">
                      <button 
                        onClick={() => handleOpenModal(item)}
                        className="text-indigo-600 hover:text-indigo-900 mr-3"
                      >
                        <Edit2 className="w-4 h-4" />
                      </button>
                      <button 
                        onClick={() => handleDelete(item.id)}
                        className="text-red-600 hover:text-red-900"
                      >
                        <Trash2 className="w-4 h-4" />
                      </button>
                    </td>
                  </tr>
                ))
              )}
            </tbody>
          </table>
        </div>
      </div>

      {/* Modal */}
      {isModalOpen && (
        <div className="fixed inset-0 bg-black/50 z-50 flex items-center justify-center p-4">
          <div className="bg-white rounded-lg shadow-xl w-full max-w-lg max-h-[90vh] overflow-y-auto">
            <div className="p-6">
              <h3 className="text-xl font-bold text-gray-900 mb-4">
                {editingItem ? 'Editar Registro' : 'Nuevo Registro'}
              </h3>
              <form onSubmit={handleSubmit} className="space-y-4">
                {formFields.map((field) => (
                  <div key={field.name}>
                    <label className="block text-sm font-medium text-gray-700 mb-1">
                      {field.label} {field.required && <span className="text-red-500">*</span>}
                    </label>

                    {field.type === 'textarea' ? (
                      <textarea
                        required={field.required}
                        value={formData[field.name] || ''}
                        onChange={(e) => setFormData({...formData, [field.name]: e.target.value})}
                        className="w-full p-2 border border-gray-300 rounded-md focus:ring-2 focus:ring-indigo-500 outline-none min-h-[100px]"
                      />
                    ) : field.type === 'select' ? (
                      <select
                        required={field.required}
                        value={formData[field.name] || ''}
                        onChange={(e) => setFormData({...formData, [field.name]: e.target.value})}
                        className="w-full p-2 border border-gray-300 rounded-md focus:ring-2 focus:ring-indigo-500 outline-none bg-white"
                      >
                        <option value="">-- Seleccionar --</option>
                        {field.options?.map(opt => (
                          <option key={opt} value={opt}>{opt}</option>
                        ))}
                      </select>
                    ) : (
                      <input
                        type={field.type}
                        required={field.required}
                        placeholder={field.placeholder}
                        value={formData[field.name] || ''}
                        onChange={(e) => setFormData({...formData, [field.name]: e.target.value})}
                        className="w-full p-2 border border-gray-300 rounded-md focus:ring-2 focus:ring-indigo-500 outline-none"
                      />
                    )}
                  </div>
                ))}

                <div className="flex justify-end gap-3 pt-4">
